#include <stdio.h>

// Function to calculate the product of the geometric sequence up to n
double calculate_product(int n) {
    double product = 1.0;
    for (int i = 1; i <= n; i++) {
        product *= (1.0 + 1.0 / i);
    }
    return product;
}

// Function to fill the array with running products
void fill_array(double arr[], int n) {
    for (int i = 0; i < n; i++) {
        arr[i] = calculate_product(i + 1);
    }
}

// Function to find the maximum value in the array
double find_maximum(double arr[], int n) {
    double max_value = arr[0];
    for (int i = 1; i < n; i++) {
        if (arr[i] > max_value) {
            max_value = arr[i];
        }
    }
    return max_value;
}

int main() {
    int n;
    printf("Enter n: ");
    scanf("%d", &n);

    double array[n];
    fill_array(array, n);

    printf("The array elements are: ");
    for (int i = 0; i < n; i++) {
        printf("%.6f ", array[i]);
    }
    printf("\n");

    double max_value = find_maximum(array, n);
    printf("The maximum of the array elements is %.6f\n", max_value);

    return 0;
}

