#include <stdio.h>
#include <math.h>

void generate_alternating_sum_array(double arr[], int n) {
    if (n <= 0) return;
    arr[0] = 1.0;
    for (int i = 2; i <= n; i++) {
        arr[i-1] = arr[i-2] + pow(-1, i+1) / (i * i);
    }
}

double find_max_value(double arr[], int n) {
    if (n <= 0) return 0.0;
    double max_val = arr[0];
    for (int i = 1; i < n; i++) {
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val;
}

int main() {
    int n;
    printf("Enter n: ");
    scanf("%d", &n);

    double arr[n];
    generate_alternating_sum_array(arr, n);

    printf("The array elements are: ");
    for (int i = 0; i < n; i++) {
        printf("%.6f ", arr[i]);
    }
    printf("\n");

    double max_value = find_max_value(arr, n);
    printf("The maximum of the array elements is %.6f\n", max_value);

    return 0;
}
